import React, { Component } from 'react';
import './Btn.css';

class Btn extends Component {
    render() {
        const {
            title,
            description
        } = this.props;

        return (
            <button className="Btn">
                <div className="Btn-title">{title}</div>
            </button>
        );
    }
}

export default Btn;
